class Solution {
public:
    int appendCharacters(string s, string t) {
        int sPtr = s.size() - 1, tPtr = t.size() - 1;
        int res = t.size();
        while (sPtr >= 0 && tPtr >= 0) {
            if (s[sPtr] == t[tPtr]) {
                tPtr--;
                res--;
            }
            sPtr--;
        }
        return res;
    }
};
